import Fastify from 'fastify';
import { productService } from './services/productService';
import { transactionService } from './services/transactionService';
import { cacheService } from './services/cacheService';
import { authMiddleware } from './middleware/auth';
import { errorHandler } from './middleware/errorHandler';
import { rateLimiter } from './middleware/rateLimiter';

const app = Fastify();

app.register(rateLimiter);
app.register(authMiddleware);
app.setErrorHandler(errorHandler);

app.get('/products', async (request, reply) => {
  const products = await productService.getProducts();
  reply.send(products);
});

app.post('/transactions', async (request, reply) => {
  const { productId, amountPaid } = request.body;
  const result = await transactionService.completeTransaction(productId, amountPaid);
  reply.send(result);
});

app.get('/cache/product/:id', async (request, reply) => {
  const productId = request.params.id;
  const productDetails = await cacheService.getProductDetails(productId);
  reply.send(productDetails);
});

const start = async () => {
  try {
    await app.listen(3000);
    console.log('Server listening on http://localhost:3000');
  } catch (err) {
    app.log.error(err);
    process.exit(1);
  }
};

start();

