import db from '../db';
import { Mutex } from '../infrastructure/mutex';

export const transactionService = {
  async completeTransaction(productId: string, amountPaid: number) {
    const mutex = new Mutex(`product:${productId}`);
    if (await mutex.acquire()) {
      try {
        const product = db.prepare('SELECT * FROM products WHERE id = ?').get(productId);
        if (!product) {
          throw new Error('Product not found');
        }
        if (product.quantity <= 0) {
          throw new Error('Product out of stock');
        }
        if (amountPaid < product.price) {
          throw new Error('Insufficient funds');
        }

        const change = amountPaid - product.price;
        db.prepare('UPDATE products SET quantity = quantity - 1 WHERE id = ?').run(productId);
        db.prepare('INSERT INTO transactions (id, product_id, amount_paid, change_given, status) VALUES (?, ?, ?, ?, ?)')
          .run(`${Date.now()}`, productId, amountPaid, change, 'SUCCESS');

        return { change, status: 'SUCCESS' };
      } finally {
        await mutex.release();
      }
    } else {
      throw new Error('Could not acquire lock');
    }
  },
};

