import redisClient from '../infrastructure/redis';
import { Mutex } from '../infrastructure/mutex';

export const cacheService = {
  async getProductDetails(productId: string) {
    const cacheKey = `product:${productId}`;
    const cachedProduct = await redisClient.get(cacheKey);
    if (cachedProduct) {
      return JSON.parse(cachedProduct);
    }

    const mutex = new Mutex(cacheKey);
    if (await mutex.acquire()) {
      try {
        // Simulate fetching from DB
        const product = { id: productId, name: 'Sample Product', price: 100, quantity: 10 };
        await redisClient.set(cacheKey, JSON.stringify(product), { EX: 60 });
        return product;
      } finally {
        await mutex.release();
      }
    } else {
      throw new Error('Could not acquire lock');
    }
  },
};

